// The first argument is typically a *testing.T value.
func NewMockOpenAIComponent(t interface {
	mock.TestingT
	Cleanup(func())
}) *MockOpenAIComponent {
	mock := &MockOpenAIComponent{}
	mock.Mock.Test(t)

	t.Cleanup(func() { mock.AssertExpectations(t) })

	return mock
}
